<template>
	<div v-if="!work" class="pt-3">Project Not Found</div>
	<div v-else class="container">
		<div class="pt-5 mb-3 text-primary lead">
			<span @click="goBack" class="cursor p-1"><i class="bi bi-reply-fill"></i> project list</span>
		</div>

		<section v-if="readme">
			<div class="type lead mb-1">
				<div class="line-break">
					<a class="ml-2 text-white" :href="work.github" target="_blank">
						<i class="bi bi-github"></i> {{ work.github }}
					</a>
				</div>
				<ProjectType :type="work.type" />
				<span class="badge badge-dark ml-1" v-for="s in work.stack" :key="s">{{ s }}</span>
			</div>
			<VueMarkdownIt :source="readme" html class="work" />
		</section>

		<section v-else>
			<p class="text-danger">
				Error: Fail to load your {{ `${work.name}(${work.github})` }}. Please check if the file "
				<span class="text-primary">portfolio.md</span>" exist in your repo.
			</p>
		</section>
	</div>
</template>

<script>
	import ProjectType from '@/components/works/ProjectType';

	export default {
		data() {
			return {
				work: this.$store.state.works.find((w) => w.name === this.$route.params.name),
				readme: '',
			};
		},
		components: {
			ProjectType,
		},
		beforeMount() {
			this.$axios
				.get(`https://raw.githubusercontent.com/woolimi/${this.work.name}/master/portfolio.md`)
				.then(({ data }) => {
					this.readme = data
						.replace(/!\[.*?\]\(.*?\)/g, (s) => {
							return s.replace(
								/\(/g,
								`(https://raw.githubusercontent.com/woolimi/${this.work.name}/master/./`
							);
						})
						.replace(/<img .*>/, (s) => {
							return s
								.replace(
									/src="/g,
									`src="https://raw.githubusercontent.com/woolimi/${this.work.name}/master/./`
								)
								.replace(
									/src='/g,
									`src='https://raw.githubusercontent.com/woolimi/${this.work.name}/master/./`
								);
						});
				})
				.catch((e) => {
					console.error(e);
				});
		},
		methods: {
			goBack() {
				this.$router.go(-1);
			},
		},
	};
</script>

