<template>
	<span :class="`badge badge-${getType}`">{{ type }}</span>
</template>

<script>
	export default {
		props: {
			type: String,
		},
		computed: {
			getType() {
				if (this.type === 'personal') return 'success';
				if (this.type === 'professional') return 'danger';
				if (this.type === 'school') return 'warning';
				return 'secondary';
			},
		},
	};
</script>

